(window.webpackJsonp=window.webpackJsonp||[]).push([[408],{1679:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number}</span> <span class=\\"hljs-variable\\">n</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[][]}</span> <span class=\\"hljs-variable\\">leadership</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[][]}</span> <span class=\\"hljs-variable\\">operations</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{number[]}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> bonus = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">n, leadership, operations</span>) </span>{\\n  <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">Tree</span>(<span class=\\"hljs-params\\">parent</span>)</span>{\\n    <span class=\\"hljs-keyword\\">this</span>.self=<span class=\\"hljs-number\\">0</span>\\n    <span class=\\"hljs-keyword\\">this</span>.subAll=<span class=\\"hljs-number\\">0</span>\\n    <span class=\\"hljs-keyword\\">this</span>.parent=parent\\n    <span class=\\"hljs-keyword\\">this</span>.child=[]\\n  }\\n  Tree.prototype.add=<span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">idTree</span>)</span>{\\n    <span class=\\"hljs-keyword\\">this</span>.child.push(idTree)\\n  }\\n  Tree.prototype.addParentCoin=<span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">coin</span>)</span>{\\n    <span class=\\"hljs-keyword\\">if</span>(<span class=\\"hljs-keyword\\">this</span>.parent){\\n      <span class=\\"hljs-keyword\\">this</span>.parent.subAll+=coin\\n      <span class=\\"hljs-keyword\\">this</span>.parent.addParentCoin(coin)\\n    }\\n  }\\n  \\n  Tree.prototype.addSelfCoin=<span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">coin</span>)</span>{\\n    <span class=\\"hljs-keyword\\">this</span>.self+=coin\\n    <span class=\\"hljs-keyword\\">this</span>.addParentCoin(coin)\\n  }\\n  Tree.prototype.addCoin=<span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">coin</span>)</span>{\\n    <span class=\\"hljs-keyword\\">this</span>.self+=coin\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;<span class=\\"hljs-keyword\\">this</span>.child.length;i++){\\n      <span class=\\"hljs-keyword\\">this</span>.child[i].addCoin(coin)\\n    }\\n    <span class=\\"hljs-keyword\\">this</span>.addParentCoin(coin) \\n  }\\n  <span class=\\"hljs-keyword\\">let</span> trees=[]\\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> [p,c] <span class=\\"hljs-keyword\\">of</span> leadership){\\n    <span class=\\"hljs-keyword\\">let</span> pt=trees[p] || <span class=\\"hljs-keyword\\">new</span> Tree(<span class=\\"hljs-literal\\">null</span>)\\n    <span class=\\"hljs-keyword\\">let</span> ct=trees[c] || <span class=\\"hljs-keyword\\">new</span> Tree(<span class=\\"hljs-literal\\">null</span>)\\n    \\n    ct.parent=pt\\n    pt.child.push(ct)\\n    trees[p]=pt\\n    trees[c]=ct\\n  }\\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;n;i++){\\n    <span class=\\"hljs-keyword\\">if</span>(trees[i]==<span class=\\"hljs-literal\\">null</span>)trees[i]=<span class=\\"hljs-keyword\\">new</span> Tree(<span class=\\"hljs-literal\\">null</span>)\\n  }\\n  <span class=\\"hljs-keyword\\">let</span> res=[]\\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;operations.length;i++){\\n    <span class=\\"hljs-keyword\\">let</span> m=operations[i][<span class=\\"hljs-number\\">0</span>]\\n    <span class=\\"hljs-keyword\\">if</span>(m==<span class=\\"hljs-number\\">1</span>){\\n      trees[operations[i][<span class=\\"hljs-number\\">1</span>]].addSelfCoin(operations[i][<span class=\\"hljs-number\\">2</span>])\\n    }<span class=\\"hljs-keyword\\">else</span> <span class=\\"hljs-keyword\\">if</span>(m==<span class=\\"hljs-number\\">2</span>){\\n      trees[operations[i][<span class=\\"hljs-number\\">1</span>]].addCoin(operations[i][<span class=\\"hljs-number\\">2</span>])\\n    }<span class=\\"hljs-keyword\\">else</span> <span class=\\"hljs-keyword\\">if</span>(m==<span class=\\"hljs-number\\">3</span>){\\n      <span class=\\"hljs-keyword\\">let</span> t=trees[operations[i][<span class=\\"hljs-number\\">1</span>]]\\n      res.push((t.self+t.subAll) % <span class=\\"hljs-number\\">1000000007</span>)\\n    }\\n  }\\n  <span class=\\"hljs-keyword\\">return</span> res\\n};\\n</code></pre>\\n"],"titleSlug":"coin-bonus","hasThinking":false,"content":"<p>\u529b\u6263\u51b3\u5b9a\u7ed9\u4e00\u4e2a\u5237\u9898\u56e2\u961f\u53d1<code>LeetCoin</code>\u4f5c\u4e3a\u5956\u52b1\u3002\u540c\u65f6\uff0c\u4e3a\u4e86\u76d1\u63a7\u7ed9\u5927\u5bb6\u53d1\u4e86\u591a\u5c11<code>LeetCoin</code>\uff0c\u529b\u6263\u6709\u65f6\u5019\u4e5f\u4f1a\u8fdb\u884c\u67e5\u8be2\u3002</p>\\n\\n<p>&nbsp;</p>\\n\\n<p>\u8be5\u5237\u9898\u56e2\u961f\u7684\u7ba1\u7406\u6a21\u5f0f\u53ef\u4ee5\u7528\u4e00\u68f5\u6811\u8868\u793a\uff1a</p>\\n\\n<ol>\\n\\t<li>\u56e2\u961f\u53ea\u6709\u4e00\u4e2a\u8d1f\u8d23\u4eba\uff0c\u7f16\u53f7\u4e3a1\u3002\u9664\u4e86\u8be5\u8d1f\u8d23\u4eba\u5916\uff0c\u6bcf\u4e2a\u4eba\u6709\u4e14\u4ec5\u6709\u4e00\u4e2a\u9886\u5bfc\uff08\u8d1f\u8d23\u4eba\u6ca1\u6709\u9886\u5bfc\uff09\uff1b</li>\\n\\t<li>\u4e0d\u5b58\u5728\u5faa\u73af\u7ba1\u7406\u7684\u60c5\u51b5\uff0c\u5982A\u7ba1\u7406B\uff0cB\u7ba1\u7406C\uff0cC\u7ba1\u7406A\u3002</li>\\n</ol>\\n\\n<p>&nbsp;</p>\\n\\n<p>\u529b\u6263\u60f3\u8fdb\u884c\u7684\u64cd\u4f5c\u6709\u4ee5\u4e0b\u4e09\u79cd\uff1a</p>\\n\\n<ol>\\n\\t<li>\u7ed9\u56e2\u961f\u7684\u4e00\u4e2a\u6210\u5458\uff08\u4e5f\u53ef\u4ee5\u662f\u8d1f\u8d23\u4eba\uff09\u53d1\u4e00\u5b9a\u6570\u91cf\u7684<code>LeetCoin</code>\uff1b</li>\\n\\t<li>\u7ed9\u56e2\u961f\u7684\u4e00\u4e2a\u6210\u5458\uff08\u4e5f\u53ef\u4ee5\u662f\u8d1f\u8d23\u4eba\uff09\uff0c\u4ee5\u53ca\u4ed6/\u5979\u7ba1\u7406\u7684\u6240\u6709\u4eba\uff08\u5373\u4ed6/\u5979\u7684\u4e0b\u5c5e\u3001\u4ed6/\u5979\u4e0b\u5c5e\u7684\u4e0b\u5c5e\uff0c&hellip;&hellip;\uff09\uff0c\u53d1\u4e00\u5b9a\u6570\u91cf\u7684<code>LeetCoin</code>\uff1b</li>\\n\\t<li>\u67e5\u8be2\u67d0\u4e00\u4e2a\u6210\u5458\uff08\u4e5f\u53ef\u4ee5\u662f\u8d1f\u8d23\u4eba\uff09\uff0c\u4ee5\u53ca\u4ed6/\u5979\u7ba1\u7406\u7684\u6240\u6709\u4eba\u88ab\u53d1\u5230\u7684<code>LeetCoin</code>\u4e4b\u548c\u3002</li>\\n</ol>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u8f93\u5165\uff1a</strong></p>\\n\\n<ol>\\n\\t<li><code>N</code>\u8868\u793a\u56e2\u961f\u6210\u5458\u7684\u4e2a\u6570\uff08\u7f16\u53f7\u4e3a1\uff5eN\uff0c\u8d1f\u8d23\u4eba\u4e3a1\uff09\uff1b</li>\\n\\t<li><code>leadership</code>\u662f\u5927\u5c0f\u4e3a<code>(N&nbsp;- 1) * 2</code>\u7684\u4e8c\u7ef4\u6570\u7ec4\uff0c\u5176\u4e2d\u6bcf\u4e2a\u5143\u7d20<code>[a, b]</code>\u4ee3\u8868<code>b</code>\u662f<code>a</code>\u7684\u4e0b\u5c5e\uff1b</li>\\n\\t<li><code>operations</code>\u662f\u4e00\u4e2a\u957f\u5ea6\u4e3a<code>Q</code>\u7684\u4e8c\u7ef4\u6570\u7ec4\uff0c\u4ee3\u8868\u4ee5\u65f6\u95f4\u6392\u5e8f\u7684\u64cd\u4f5c\uff0c\u683c\u5f0f\u5982\u4e0b\uff1a\\n\\t<ol>\\n\\t\\t<li><code>operations[i][0] = 1</code>: \u4ee3\u8868\u7b2c\u4e00\u79cd\u64cd\u4f5c\uff0c<code>operations[i][1]</code>\u4ee3\u8868\u6210\u5458\u7684\u7f16\u53f7\uff0c<code>operations[i][2]</code>\u4ee3\u8868<code>LeetCoin</code>\u7684\u6570\u91cf\uff1b</li>\\n\\t\\t<li><code>operations[i][0] = 2</code>: \u4ee3\u8868\u7b2c\u4e8c\u79cd\u64cd\u4f5c\uff0c<code>operations[i][1]</code>\u4ee3\u8868\u6210\u5458\u7684\u7f16\u53f7\uff0c<code>operations[i][2]</code>\u4ee3\u8868<code>LeetCoin</code>\u7684\u6570\u91cf\uff1b</li>\\n\\t\\t<li><code>operations[i][0] = 3</code>: \u4ee3\u8868\u7b2c\u4e09\u79cd\u64cd\u4f5c\uff0c<code>operations[i][1]</code>\u4ee3\u8868\u6210\u5458\u7684\u7f16\u53f7\uff1b</li>\\n\\t</ol>\\n\\t</li>\\n</ol>\\n\\n<p><strong>\u8f93\u51fa\uff1a</strong></p>\\n\\n<p>\u8fd4\u56de\u4e00\u4e2a\u6570\u7ec4\uff0c\u6570\u7ec4\u91cc\u662f\u6bcf\u6b21<strong>\u67e5\u8be2</strong>\u7684\u8fd4\u56de\u503c\uff08\u53d1<code>LeetCoin</code>\u7684\u64cd\u4f5c\u4e0d\u9700\u8981\u4efb\u4f55\u8fd4\u56de\u503c\uff09\u3002\u7531\u4e8e\u53d1\u7684<code>LeetCoin</code>\u5f88\u591a\uff0c\u8bf7\u628a\u6bcf\u6b21\u67e5\u8be2\u7684\u7ed3\u679c\u6a21<code>1e9+7 (1000000007)</code>\u3002</p>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>N = 6, leadership = [[1, 2], [1, 6], [2, 3], [2, 5], [1, 4]], operations = [[1, 1, 500], [2, 2, 50], [3, 1], [2, 6, 15], [3, 1]]\\n<strong>\u8f93\u51fa\uff1a</strong>[650, 665]\\n<strong>\u89e3\u91ca\uff1a</strong>\u56e2\u961f\u7684\u7ba1\u7406\u5173\u7cfb\u89c1\u4e0b\u56fe\u3002\\n\u7b2c\u4e00\u6b21\u67e5\u8be2\u65f6\uff0c\u6bcf\u4e2a\u6210\u5458\u5f97\u5230\u7684LeetCoin\u7684\u6570\u91cf\u5206\u522b\u4e3a\uff08\u6309\u7f16\u53f7\u987a\u5e8f\uff09\uff1a500, 50, 50, 0, 50, 0;\\n\u7b2c\u4e8c\u6b21\u67e5\u8be2\u65f6\uff0c\u6bcf\u4e2a\u6210\u5458\u5f97\u5230\u7684LeetCoin\u7684\u6570\u91cf\u5206\u522b\u4e3a\uff08\u6309\u7f16\u53f7\u987a\u5e8f\uff09\uff1a500, 50, 50, 0, 50, 15.\\n</pre>\\n\\n<p><img alt=\\"\\" src=\\"https://assets.leetcode-cn.com/aliyun-lc-upload/uploads/2019/09/09/coin_example_1.jpg\\" style=\\"height: 344px; width: 300px;\\"></p>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u9650\u5236\uff1a</strong></p>\\n\\n<ol>\\n\\t<li><code>1 &lt;= N &lt;= 50000</code></li>\\n\\t<li><code>1 &lt;= Q &lt;= 50000</code></li>\\n\\t<li><code>operations[i][0] != 3 \u65f6\uff0c1 &lt;= operations[i][2]&nbsp;&lt;= 5000</code></li>\\n</ol>\\n","title":"LCP 05. \u53d1 LeetCoin","relatedTags":[],"difficult":"Hard","lang":["javascript"],"uniqueID":"LCP 05"}')}}]);